export const COMPONENT_METAS: ComponentMeta[] = COMPONENTS.map((c) => ({
  ...c,
  snippets: SNIPPETS[c.tag] ?? { component: '// (no snippet)', vanilla: '', react: '' },
}));

export function getComponent(tag: string): ComponentMeta | undefined {
  return COMPONENT_METAS.find((c) => c.tag === tag);
}

export function componentsByCategory(cat: ComponentSpec['category']): ComponentMeta[] {
  return COMPONENT_METAS.filter((c) => c.category === cat);
}
